import{_ as a,o as r,c as t,ag as o}from"./chunks/framework.eQLvDOR_.js";const d=JSON.parse('{"title":"Hermes 多 Agent 框架 (Hermes Agent Framework)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/concepts/hermes-agent-framework.md","filePath":"wiki/concepts/hermes-agent-framework.md","lastUpdated":null}'),n={name:"wiki/concepts/hermes-agent-framework.md"};function i(l,e,s,m,h,g){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="hermes-多-agent-框架-hermes-agent-framework" tabindex="-1">Hermes 多 Agent 框架 (Hermes Agent Framework) <a class="header-anchor" href="#hermes-多-agent-框架-hermes-agent-framework" aria-label="Permalink to &quot;Hermes 多 Agent 框架 (Hermes Agent Framework)&quot;">​</a></h1><h2 id="核心定义" tabindex="-1">核心定义 <a class="header-anchor" href="#核心定义" aria-label="Permalink to &quot;核心定义&quot;">​</a></h2><p>一种基于强隔离和独立 Profile 设计的多 Agent 部署和协同框架，强调“从一个 Agent 到一支队伍”的工程落地。</p><h2 id="架构特点" tabindex="-1">架构特点 <a class="header-anchor" href="#架构特点" aria-label="Permalink to &quot;架构特点&quot;">​</a></h2><ul><li><strong>Profile 隔离</strong>: 每个 Agent 拥有独立的运行环境、上下文沙盒和工具集，避免多任务相互污染。</li><li><strong>Soul 提示词 (SOUL.md)</strong>: 为每个 Agent 注入独立的人格和行为准则，使其在团队中扮演特定的专业角色。</li><li><strong>高阶工具配置</strong>: 支持细粒度的底层控制，使 Agent 能与外部系统（如 Telegram Bot、外部 API）无缝集成。</li></ul><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>适用于需要并发执行多项互不干扰的任务、或需要不同&quot;性格/专业&quot; Agent 协作的复杂工作流。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li>[[multi-agent-orchestrator]]</li><li>[[agent-profile-isolation]]</li></ul>',9)])])}const u=a(n,[["render",i]]);export{d as __pageData,u as default};
